// Leer agentes humanos desde los datos enviados por el Router
const input = $('Recibir Datos del Router').first().json;
const allAgents = Array.isArray(input.humanAgents) ? input.humanAgents : [];
const availableAgents = allAgents.filter(a => a.available === true);
return [{ json: { available: availableAgents.length > 0, agentes: availableAgents, message: availableAgents.length > 0 ? `${availableAgents.length} agente(s) disponible(s)` : 'Sin agentes disponibles' } }];

const input = $('Recibir Datos del Router').first().json;
const agentes = $input.all().map(i => i.json);
const hayAgentes = agentes.length > 0 && !!agentes[0].name;

let responseText;
let actionTaken;

if (hayAgentes) {
  const agente = agentes[0]; // Asignar al primer agente disponible
  responseText = `Entiendo que necesitas hablar con una persona, ${input.pushName || 'estimado cliente'}. Te estoy conectando con ${agente.name}. Un agente te contactar\u00e1 en breve por este mismo chat. Gracias por tu paciencia.`;
  actionTaken = 'agente_asignado';
} else {
  responseText = `Entiendo que necesitas hablar con una persona, ${input.pushName || 'estimado cliente'}. En este momento no hay agentes disponibles. Hemos registrado tu solicitud y un agente te contactar\u00e1 a la brevedad posible. Gracias por tu paciencia.`;
  actionTaken = 'ticket_creado';
}

return [{
  json: {
    response: responseText,
    phone: input.phone,
    tenantId: input.tenantId,
    intent_handled: 'humano',
    action_taken: actionTaken,
    metadata: {
      pushName: input.pushName,
      original_message: input.message,
      agentes_disponibles: hayAgentes,
      agente_asignado: hayAgentes ? agentes[0].name : null
    }
  }
}];

// Registro de escalamiento: reemplaza insercion directa en MongoDB
// En produccion usar Backend API cuando este implementado
const input = $input.first().json;
return [{ json: { ...input, escalated: true, timestamp: new Date().toISOString(), logged: true } }];

const escalResult = $('Evaluar Disponibilidad').first().json;
const emailResult = $input.first().json;
return [{
  json: {
    response: escalResult.response,
    phone: escalResult.phone,
    tenantId: escalResult.tenantId,
    intent_handled: escalResult.intent_handled,
    action_taken: escalResult.action_taken,
    metadata: escalResult.metadata,
    reason: (escalResult.metadata && escalResult.metadata.original_message) || 'Solicitud de agente humano',
    agente_asignado: (escalResult.metadata && escalResult.metadata.agente_asignado) || null,
    timestamp: new Date().toISOString(),
    emailSent: emailResult.ok === true
  }
}];

const input = $('Recibir Datos del Router').first().json;
const evalResult = $('Evaluar Disponibilidad').first().json;
return [{
  json: {
    // Email payload
    tenantId: input.tenantId,
    tenantEmail: input.tenantEmail || '',
    clientPhone: input.phone || '',
    clientName: input.pushName || 'Cliente',
    clientMessage: input.message || '',
    businessName: input.businessName || input.tenantId,
    // Escalation response to pass forward
    response: evalResult.response,
    phone: evalResult.phone,
    intent_handled: evalResult.intent_handled,
    action_taken: evalResult.action_taken,
    metadata: evalResult.metadata
  }
}];
